compliant:
public ActionResult Welcome(string name)
{
    ViewBag.Name = name;
    return View();
    // Compliant: Request validation enabled by default
}

public class HomeController : Controller
{
    public ActionResult ProcessComment(string comment)
    {
        string sanitized = HtmlEncoder.Default.Encode(comment);
        return Content(sanitized);
        // Compliant: Manual validation and encoding
    }
}

public ActionResult SubmitData([FromBody] string data)
{
    if (!IsValidInput(data))
        return BadRequest("Invalid input");

    ProcessData(data);
    return Ok();
    // Compliant: Custom validation instead of disabling request validation
}
